using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

var options = new JsonSerializerOptions
{
    // The default resolver makes metadata available for any type on demand.
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// ─── 1. Strongly-typed retrieval: JsonTypeInfo<T> ───────────────────
//
// GetTypeInfo<T>() is a generic convenience that returns JsonTypeInfo<T>
// directly — no casting required.

JsonTypeInfo<Person> personMeta = options.GetTypeInfo<Person>();
Console.WriteLine($"Got typed metadata for: {personMeta.Type.Name}");
Console.WriteLine($"  Kind           : {personMeta.Kind}");
Console.WriteLine($"  Property count : {personMeta.Properties.Count}");

string json = JsonSerializer.Serialize(new Person("Ada", 36), personMeta);
Console.WriteLine($"  Round-trip JSON: {json}");

// ─── 2. Probe without throwing: TryGetTypeInfo ──────────────────────
//
// TryGetTypeInfo returns false instead of throwing when metadata for
// the requested type isn't available.

// 2a. Type that IS resolvable
if (options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info))
{
    Console.WriteLine($"\nTryGetTypeInfo(Person) succeeded — Kind: {info!.Kind}");
}

// 2b. Type that is NOT resolvable (empty resolver → no metadata)
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = new EmptyResolver()
};

if (limited.TryGetTypeInfo(typeof(Person), out _))
{
    Console.WriteLine("\nUnexpectedly found metadata!");
}
else
{
    Console.WriteLine("\nTryGetTypeInfo(Person) on empty resolver → false (no exception)");
}

// ─────────────────────────────────────────────────────────────────────
record Person(string Name, int Age);

/// <summary>A resolver that deliberately resolves nothing.</summary>
sealed class EmptyResolver : IJsonTypeInfoResolver
{
    public JsonTypeInfo? GetTypeInfo(Type type, JsonSerializerOptions options) => null;
}

